// Time:  O(n + e)
// Space: O(n + e)

class Solution {
public:
    enum Status { UNVISITED, VISITING, DONE };

    bool leadsToDestination(int n, vector<vector<int>>& edges, int source, int destination) {
        unordered_map<int, vector<int>> children;
        for (const auto& edge : edges) {
            children[edge[0]].emplace_back(edge[1]);
        }
        vector<Status> status(n);
        return dfs(children, source, destination, &status);
    }

private:
    bool dfs(const unordered_map<int, vector<int>>& children,
             int node,
             int destination,
             vector<Status> *status) {

        if ((*status)[node] == DONE) {
            return true;
        }
        if ((*status)[node] == VISITING) {
            return false;
        }
        (*status)[node] = VISITING;
        if (!children.count(node) && node != destination) {
            return false;
        }
        if (children.count(node)) {
            for (const auto& child : children.at(node)) {
                if (!dfs(children, child, destination, status)) {
                    return false;
                }
            }
        }
        (*status)[node] = DONE;
        return true;
    }
};

# Time:  O(n + e)
# Space: O(n + e)

import collections


class Solution(object):
    def leadsToDestination(self, n, edges, source, destination):
        """
        :type n: int
        :type edges: List[List[int]]
        :type source: int
        :type destination: int
        :rtype: bool
        """
        UNVISITED, VISITING, DONE = range(3)
        def dfs(children, node, destination, status):
            if status[node] == DONE:
                return True
            if status[node] == VISITING:
                return False
            status[node] = VISITING
            if node not in children and node != destination:
                return False
            if node in children:
                for child in children[node]:
                    if not dfs(children, child, destination, status):
                        return False
            status[node] = DONE
            return True

        children = collections.defaultdict(list)
        for parent, child in edges:
            children[parent].append(child)
        return dfs(children, source, destination, [0]*n)
